const row = $input.first().json;
const title = row.title || 'Kein Titel';
const slug = row.topic_slug || (row.post_id || 'artikel').toLowerCase().replace(/[^a-z0-9]+/g, '-');
const body = row.body_markdown || '';
const meta = row.meta_description || title;
const keywords = row.keywords || '';
const pubAt = row.published_at || new Date().toISOString();
const isDryRun = row.dry_run === 'true' || row.dry_run === true;
const dateISO = pubAt.slice(0, 10);
const dateObj = new Date(pubAt);
const dateDE = dateObj.toLocaleDateString('de-DE', { year: 'numeric', month: 'long', day: 'numeric' });
const filename = `website/blog/${dateISO}-${slug}.html`;
const articlePath = `blog/${dateISO}-${slug}.html`;
const articleUrl = `https://ak-assistance.de/blog/${dateISO}-${slug}.html`;

function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function inline(s) {
  return esc(s)
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/\[(.+?)\]\((.+?)\)/g, (_, t, u) => {
      const safe = /^https?:\/\//i.test(u) ? u : '#';
      return '<a href="' + safe + '" target="_blank" rel="noopener noreferrer">' + t + '</a>';
    });
}
function mdToHtml(md) {
  const lines = (md || '').split('\n');
  let html = '', inOl = false, inUl = false;
  for (const line of lines) {
    if (line.startsWith('# ')) { if(inOl){html+='</ol>\n';inOl=false;} if(inUl){html+='</ul>\n';inUl=false;} html += '<h1>' + esc(line.slice(2).trim()) + '</h1>\n'; }
    else if (line.startsWith('## ')) { if(inOl){html+='</ol>\n';inOl=false;} if(inUl){html+='</ul>\n';inUl=false;} html += '<h2>' + esc(line.slice(3).trim()) + '</h2>\n'; }
    else if (line.startsWith('### ')) { if(inOl){html+='</ol>\n';inOl=false;} if(inUl){html+='</ul>\n';inUl=false;} html += '<h3>' + esc(line.slice(4).trim()) + '</h3>\n'; }
    else if (/^\d+\.\s/.test(line)) { if(inUl){html+='</ul>\n';inUl=false;} if(!inOl){html+='<ol>\n';inOl=true;} html += '<li>' + inline(line.replace(/^\d+\.\s/, '')) + '</li>\n'; }
    else if (/^[-*]\s/.test(line)) { if(inOl){html+='</ol>\n';inOl=false;} if(!inUl){html+='<ul>\n';inUl=true;} html += '<li>' + inline(line.replace(/^[-*]\s/, '')) + '</li>\n'; }
    else if (line.trim() === '') { if(inOl){html+='</ol>\n';inOl=false;} if(inUl){html+='</ul>\n';inUl=false;} }
    else { if(inOl){html+='</ol>\n';inOl=false;} if(inUl){html+='</ul>\n';inUl=false;} html += '<p>' + inline(line) + '</p>\n'; }
  }
  if(inOl) html+='</ol>\n'; if(inUl) html+='</ul>\n';
  return html;
}
const bodyHtml = mdToHtml(body);
const tags = (keywords||'').split(',').map(k=>k.trim()).filter(Boolean).map(k=>`<span class="article-tag">${esc(k)}</span>`).join('');
