const contentBase64 = Buffer.from(html).toString('base64');
const indexEntry = {
  path: articlePath, title, meta_description: meta, published_at: pubAt,
  keywords: (keywords||'').split(',').map(k=>k.trim()).filter(Boolean)
};
return [{ json: { filename, articleUrl, articlePath, slug, dateISO, title, contentBase64, indexEntry, dry_run: isDryRun } }];

const ghResponse = $input.first().json;
const sha = ghResponse.sha || '';
let existing = [];
try {
  const raw = Buffer.from(ghResponse.content || '', 'base64').toString('utf-8') || '[]';
  existing = JSON.parse(raw);
  if (!Array.isArray(existing)) existing = [];
} catch(e) { existing = []; }
const newEntry = $('HTML und Pfad berechnen').first().json.indexEntry;
const filtered = existing.filter(e => e.path !== newEntry.path);
filtered.unshift(newEntry);
const updatedContent = Buffer.from(JSON.stringify(filtered, null, 2)).toString('base64');
return [{ json: { sha, updatedContent } }];

